using System.ComponentModel.DataAnnotations;

namespace sv_452a45959c7448b2b67f0e9bfbf1f560.Models;

public class ReviewModel
{
    [Required(ErrorMessage = "Product name is required.")]
    [Display(Name = "Product Name")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title cannot exceed 100 characters.")]
    [Display(Name = "Review Title")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body cannot exceed 2000 characters.")]
    [Display(Name = "Review Body")]
    public string ReviewBody { get; set; } = string.Empty;
}

using sv_452a45959c7448b2b67f0e9bfbf1f560.Models;

namespace sv_452a45959c7448b2b67f0e9bfbf1f560.Services;

public class ReviewService
{
    /// <summary>
    /// Validates the review against server-side business rules and submits it if valid.
    /// Returns a dictionary of field-specific errors (empty if successful).
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAndSubmitAsync(ReviewModel review)
    {
        var errors = new Dictionary<string, string>();

        if (review.ReviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(review.ReviewTitle)] = "Review title contains inappropriate language.";
        }

        // Stub: additional server-side validation rules can be added here.

        return Task.FromResult(errors);
    }
}

@page "/write-review"
@rendermode InteractiveServer
@using sv_452a45959c7448b2b67f0e9bfbf1f560.Models
@using sv_452a45959c7448b2b67f0e9bfbf1f560.Services
@inject ReviewService ReviewService

<PageTitle>Write a Review</PageTitle>

<h3>Write a Review</h3>

@if (submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Thank you!</h4>
        <p>Your review has been submitted successfully.</p>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="review-form">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="productName" class="form-label">Product Name</label>
            <InputText id="productName" class="form-control" @bind-Value="model.ProductName" />
            <ValidationMessage For="() => model.ProductName" />
        </div>

        <div class="mb-3">
            <label for="rating" class="form-label">Rating</label>
            <InputNumber id="rating" class="form-control" @bind-Value="model.Rating" min="1" max="5" />
            <ValidationMessage For="() => model.Rating" />
        </div>

        <div class="mb-3">
            <label for="reviewTitle" class="form-label">Review Title</label>
            <InputText id="reviewTitle" class="form-control" @bind-Value="model.ReviewTitle" />
            <ValidationMessage For="() => model.ReviewTitle" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewTitle)))
            {
                <div class="validation-message">@serverErrors[nameof(model.ReviewTitle)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewBody" class="form-label">Review Body</label>
            <InputTextArea id="reviewBody" class="form-control" rows="5" @bind-Value="model.ReviewBody" />
            <ValidationMessage For="() => model.ReviewBody" />
        </div>

        <div class="mb-3">
            <label for="photos" class="form-label">Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile id="photos" class="form-control" OnChange="OnPhotosSelected"
                       multiple accept=".jpg,.jpeg,.png" />
            @if (photoErrors.Count > 0)
            {
                @foreach (var error in photoErrors)
                {
                    <div class="validation-message">@error</div>
                }
            }
            @if (selectedPhotos.Count > 0)
            {
                <ul class="list-group mt-2">
                    @foreach (var photo in selectedPhotos)
                    {
                        <li class="list-group-item d-flex justify-content-between align-items-center">
                            @photo.Name
                            <span class="badge bg-secondary">@FormatSize(photo.Size)</span>
                        </li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Review</span>
            }
        </button>
    </EditForm>
}

@code {
    private ReviewModel model = new();
    private List<IBrowserFile> selectedPhotos = new();
    private List<string> photoErrors = new();
    private Dictionary<string, string> serverErrors = new();
    private bool submitted;
    private bool isSubmitting;

    private const int MaxPhotos = 3;
    private const long MaxPhotoSize = 5 * 1024 * 1024; // 5 MB
    private static readonly string[] AllowedExtensions = [".jpg", ".jpeg", ".png"];

    private void OnPhotosSelected(InputFileChangeEventArgs e)
    {
        photoErrors.Clear();
        serverErrors.Clear();
        var files = e.GetMultipleFiles(MaxPhotos + 1); // read one extra to detect overflow

        if (files.Count > MaxPhotos)
        {
            photoErrors.Add($"You can upload at most {MaxPhotos} photos.");
            selectedPhotos.Clear();
            return;
        }

        var validFiles = new List<IBrowserFile>();

        foreach (var file in files)
        {
            var ext = Path.GetExtension(file.Name).ToLowerInvariant();
            if (!AllowedExtensions.Contains(ext))
            {
                photoErrors.Add($"'{file.Name}' is not a supported format. Use JPG or PNG.");
                continue;
            }

            if (file.Size > MaxPhotoSize)
            {
                photoErrors.Add($"'{file.Name}' exceeds the 5 MB size limit.");
                continue;
            }

            validFiles.Add(file);
        }

        selectedPhotos = validFiles;
    }

    private async Task HandleSubmit()
    {
        serverErrors.Clear();
        isSubmitting = true;

        try
        {
            var errors = await ReviewService.ValidateAndSubmitAsync(model);

            if (errors.Count > 0)
            {
                serverErrors = errors;
                return;
            }

            // In a real app you would read the photo streams here via
            // file.OpenReadStream(MaxPhotoSize) and persist them.

            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F2} MB"
    };
}

